queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasBenefits ?child ; p:hasFrequent_Flyer_Program ?parent . } GROUP BY ?child }
  ?child p:Description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Frequent_Flyer_Program } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?programid ?description WHERE {
  ?frequent_flyer_program_benefits a :Frequent_Flyer_Program_Benefits .
  ?benefits a :Benefits .
  ?frequent_flyer_program_benefits p:hasBenefits ?benefits .
  ?frequent_flyer_program a :Frequent_Flyer_Program .
  ?frequent_flyer_program_benefits p:hasFrequent_Flyer_Program ?frequent_flyer_program .
  ?frequent_flyer_program p:ProgramId ?programid .
  ?benefits p:Description ?description .
} }
  collective: { SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasBenefits ?child ; p:hasFrequent_Flyer_Program ?parent . } GROUP BY ?child }
  ?child p:Description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Frequent_Flyer_Program } }
  FILTER(?nf = ?total)
} }
}
